    // Traverse the array
    for (let i = 0; i < n - 1; i++) {
        let minIndex = i; // Assume current index is the minimum

        // Find the minimum element in the remaining unsorted array
        for (let j = i + 1; j < n; j++) {
            if (arr[j] < arr[minIndex]) {
                minIndex = j; // Update minIndex if smaller element is found
            }
