        // Swap the found minimum with the first element of unsorted part
        let temp = arr[minIndex];
        arr[minIndex] = arr[i];
        arr[i] = temp;
    }

    // Print the sorted array
    console.log("After selection sort:");
    console.log(arr.join(" "));
}

